const event = $('Execute Workflow Trigger').item.json;
const row = $json || {};
const safeArr = v => Array.isArray(v) ? v : [];
const safeObj = v => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

const kpis = safeObj(row.kpis);
const ranking = safeArr(row.ranking);
const hitos = safeArr(row.hitos_proximos);
const ptos = safeArr(row.ptos_activos);
const teamRates = safeArr(row.team_rates);
const totalTeam = teamRates.length || 4;

const PROJECT_END = new Date('2026-06-10');
const now = new Date();
const diasRestantes = Math.max(0, Math.ceil((PROJECT_END - now) / 86400000));
const semanasRestantes = Math.max(1, Math.ceil(diasRestantes / 7));

const progreso = Number(row.progreso_pct || 0);
const totalTarjetas = Number(row.total_tarjetas || 1);
const completadas = Number(row.total_completadas || 0);
const pendientes = Number(row.tareas_pendientes || totalTarjetas - completadas);
const completadas7d = Number(row.completadas_7d || 0);
const completadas14d = Number(row.completadas_14d || 0);

// Velocity
const velocidad7d = completadas7d / 7;
const velocidad14d = completadas14d / 14;
const velocidadPromedio = (velocidad7d + velocidad14d) / 2;

// PTO impact
const hoy = new Date();
const ptosActivos = ptos.filter(p => {
  const inicio = new Date(p.fecha_inicio);
  const fin = new Date(p.fecha_fin);
  return inicio <= PROJECT_END && fin >= hoy;
});

let diasPTOTotal = 0;
const ptoDetalle = [];
for (const p of ptosActivos) {
  const inicio = new Date(p.fecha_inicio) < hoy ? hoy : new Date(p.fecha_inicio);
  const fin = new Date(p.fecha_fin) > PROJECT_END ? PROJECT_END : new Date(p.fecha_fin);
  const dias = Math.max(0, Math.ceil((fin - inicio) / 86400000));
  diasPTOTotal += dias;
  ptoDetalle.push(`${p.miembro}: ${dias}d (${p.motivo || 'PTO'}, ${new Date(p.fecha_inicio).toLocaleDateString('es-EC')} - ${new Date(p.fecha_fin).toLocaleDateString('es-EC')})`);
}

// Capacity reduction from PTO
const diasEquipoTotal = diasRestantes * totalTeam;
const diasEfectivos = Math.max(1, diasEquipoTotal - diasPTOTotal);
const capacidadPct = Number(((diasEfectivos / diasEquipoTotal) * 100).toFixed(1));
const velocidadAjustada = velocidadPromedio * (capacidadPct / 100);

// Forecasting
const diasParaCerrar = velocidadAjustada > 0 ? Math.ceil(pendientes / velocidadAjustada) : 999;
const fechaEstimadaCierre = new Date(now.getTime() + diasParaCerrar * 86400000);
const enTiempo = fechaEstimadaCierre <= PROJECT_END;

// Scenarios
const escenarios = [
  { nombre: 'Optimista (+20% velocidad)', vel: velocidadAjustada * 1.2, dias: Math.ceil(pendientes / (velocidadAjustada * 1.2)), en_tiempo: new Date(now.getTime() + Math.ceil(pendientes / (velocidadAjustada * 1.2)) * 86400000) <= PROJECT_END },
  { nombre: 'Base (actual)', vel: velocidadAjustada, dias: diasParaCerrar, en_tiempo: enTiempo },
  { nombre: 'Pesimista (-20% velocidad)', vel: velocidadAjustada * 0.8, dias: Math.ceil(pendientes / (velocidadAjustada * 0.8)), en_tiempo: new Date(now.getTime() + Math.ceil(pendientes / (velocidadAjustada * 0.8)) * 86400000) <= PROJECT_END },
  { nombre: 'Con 1 miembro menos', vel: velocidadAjustada * ((totalTeam - 1) / totalTeam), dias: Math.ceil(pendientes / (velocidadAjustada * ((totalTeam - 1) / totalTeam))), en_tiempo: false }
];

const escenariosStr = escenarios.map(e => `${e.nombre}: ${e.vel.toFixed(2)} tareas/dia, ${e.dias}d para cerrar ${e.en_tiempo ? '(A TIEMPO)' : '(FUERA DE PLAZO)'}`).join('\n');

const rankingStr = ranking.slice(0, 5).map(r => `${r.trello_name}: done=${r.tareas_done}, pending=${r.tareas_pending}, overdue=${r.tareas_overdue}`).join(' | ');

const hitosStr = hitos.slice(0, 4).map(h => `${h.nombre} en ${h.dias_faltan}d`).join(', ');

const ptoStr = ptoDetalle.length > 0 ? ptoDetalle.join('\n') : 'Ningún PTO registrado.';

let riesgoFecha = 'bajo';
if (!enTiempo) riesgoFecha = 'critico';
else if (diasParaCerrar > diasRestantes * 0.85) riesgoFecha = 'alto';
else if (diasParaCerrar > diasRestantes * 0.7) riesgoFecha = 'medio';

const prompt = `Eres el Capacity Forecaster del proyecto PetSafe (NestJS+Angular, cierre 10-jun-2026). Analiza capacidad del equipo, velocidad, PTOs y genera proyecciones. Texto plano, SIN markdown, SIN asteriscos, en español.\n\nDATA ACTUAL\nProgreso: ${progreso}% (${completadas}/${totalTarjetas})\nPendientes: ${pendientes} tareas\nDias hasta cierre: ${diasRestantes} (${semanasRestantes} semanas)\nEquipo activo: ${totalTeam} miembros\n\nVELOCIDAD\n7d: ${velocidad7d.toFixed(2)} tareas/dia | 14d: ${velocidad14d.toFixed(2)} | Promedio: ${velocidadPromedio.toFixed(2)}\nAjustada por PTOs: ${velocidadAjustada.toFixed(2)} tareas/dia\n\nPTOs REGISTRADOS\n${ptoStr}\nDias-persona perdidos por PTO: ${diasPTOTotal} de ${diasEquipoTotal} disponibles\nCapacidad efectiva: ${capacidadPct}%\n\nPROYECCION\nDias estimados para cerrar (ajustado): ${diasParaCerrar}\nFecha estimada cierre: ${fechaEstimadaCierre.toLocaleDateString('es-EC')}\nEn tiempo: ${enTiempo ? 'SI' : 'NO - FUERA DE PLAZO'}\nRiesgo de fecha: ${riesgoFecha.toUpperCase()}\n\nESCENARIOS\n${escenariosStr}\n\nCARGA EQUIPO: ${rankingStr}\nHITOS PROXIMOS: ${hitosStr}\n\nEstructura obligatoria:\nCAPACIDAD: Estado de capacidad del equipo y efecto de PTOs.\nPROYECCION: Escenario mas probable y si se cumple el 10-jun-2026.\nACCIONES: 3 acciones por nombre (FG, DM, DP, JA) para garantizar entrega.\nSI NO SE LLEGA: Plan B concreto (que recortar, que priorizar, que negociar con cliente).`;

return [{ json: {
  correlation_id: event.correlation_id || `cap-${Date.now()}`,
  event_type: event.event_type || 'capacity_forecast',
  prompt, riesgoFecha, capacidadPct, velocidadAjustada, diasParaCerrar,
  fechaEstimadaCierre: fechaEstimadaCierre.toLocaleDateString('es-EC'),
  enTiempo, diasRestantes, pendientes, progreso, escenarios, ptoStr, diasPTOTotal
}}];

const raw = $json.text ?? $json.output ?? $json.response ?? '';
const iaText = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
const ctx = $('Build Capacity Context').item.json;
const rE = { critico: '🔴', alto: '🟠', medio: '🟡', bajo: '🟢' }[ctx.riesgoFecha] || '⚪';
const colorMap = { critico: 15158332, alto: 16744192, medio: 16761095, bajo: 3066993 };
const escStr = ctx.escenarios.map(e => `${e.en_tiempo ? '✅' : '❌'} ${e.nombre}: ${e.dias}d`).join('\n');
const discord_payload = {
  username: 'PM PetSafe · Capacity',
  embeds: [{
    title: `${rE} Forecast de Capacidad · ${ctx.diasRestantes}d hasta cierre`,
    description: `Riesgo de fecha: **${ctx.riesgoFecha.toUpperCase()}** · Capacidad efectiva: **${ctx.capacidadPct}%** · ${ctx.enTiempo ? '✅ En tiempo' : '❌ FUERA DE PLAZO'}`,
    color: colorMap[ctx.riesgoFecha] || 3066993,
    fields: [
      { name: '📊 Velocidad', value: `**${ctx.velocidadAjustada.toFixed(2)}** tareas/día (ajustada por PTOs)`, inline: true },
      { name: '📅 Cierre Estimado', value: `**${ctx.fechaEstimadaCierre}** (${ctx.diasParaCerrar}d)`, inline: true },
      { name: '🏖️ PTOs', value: ctx.ptoStr.slice(0, 500) || 'Ninguno', inline: false },
      { name: '🔮 Escenarios', value: escStr.slice(0, 800), inline: false },
      { name: '🤖 Análisis IA', value: iaText.slice(0, 900), inline: false }
    ],
    footer: { text: 'Capacity Forecaster · PM PetSafe AI' },
    timestamp: new Date().toISOString()
  }]
};
return [{ json: {
  correlation_id: ctx.correlation_id, agent_role: 'Capacity Forecaster', decision_type: 'capacity_forecast',
  input_summary: `Capacity: ${ctx.capacidadPct}% eff, ${ctx.diasParaCerrar}d to close, risk=${ctx.riesgoFecha}`.slice(0,500),
  context_used: { capacidadPct: ctx.capacidadPct, diasParaCerrar: ctx.diasParaCerrar, riesgoFecha: ctx.riesgoFecha },
  evidence: { escenarios: ctx.escenarios, ia: iaText.slice(0,1000) },
  decision: { riesgoFecha: ctx.riesgoFecha, enTiempo: ctx.enTiempo, fechaEstimada: ctx.fechaEstimadaCierre },
  recommendation: iaText.slice(0,500), confidence: 0.85,
  risk_level: ctx.riesgoFecha === 'critico' ? 'high' : ctx.riesgoFecha === 'alto' ? 'high' : 'medium',
  requires_human_approval: !ctx.enTiempo, discord_payload, ia_text: iaText,
  forecast_data: { velocidad: ctx.velocidadAjustada, capacidad: ctx.capacidadPct, dias: ctx.diasParaCerrar, pendientes: ctx.pendientes, ptos: ctx.diasPTOTotal, escenarios: ctx.escenarios }
}}];
